import json
from pydantic import BaseModel, ValidationError
from openai import OpenAI

client = OpenAI()

class Recommendation(BaseModel):
    product_name: str
    price_usd: float
    confidence: float
    reasons: list[str]

SYSTEM = '''You are a product recommendation assistant.
Always respond with valid JSON: {"product_name": str, "price_usd": float, "confidence": float, "reasons": [str]}'''

def get_recommendation(query: str, max_retries: int = 2) -> Recommendation:
    messages = [{'role':'system','content':SYSTEM}, {'role':'user','content':query}]
    for attempt in range(max_retries + 1):
        raw = client.chat.completions.create(
            model='gpt-4o', messages=messages,
            response_format={'type': 'json_object'},
        ).choices[0].message.content
        try:
            return Recommendation(**json.loads(raw))
        except (json.JSONDecodeError, ValidationError) as e:
            if attempt == max_retries:
                raise RuntimeError(f'Format rail failed: {e}')
            messages += [{'role':'assistant','content':raw},
                         {'role':'user','content':f'Format error: {e}. Please correct.'}]

SENSITIVE_RULES = {
    'self_harm': {
        'keywords': ['suicide', 'self-harm', 'kill myself'],
        'prefix': 'If you are in crisis, please contact the 988 Lifeline (call/text 988).\n\n',
        'continue': True,
    },
    'legal': {
        'keywords': ['is it legal', 'should i sue', 'legal advice'],
        'suffix': '\n\n*General information only — not legal advice. Consult a qualified attorney.*',
        'continue': True,
    },
}

def apply_sensitive_rail(query: str, response: str) -> str:
    for rule in SENSITIVE_RULES.values():
        if any(kw in query.lower() for kw in rule['keywords']):
            if not rule.get('continue'):
                return rule.get('prefix', '').strip()
            return rule.get('prefix','') + response + rule.get('suffix','')
    return response

TOOL_POLICY = {
    'read_file':    {'allowed': True,  'path_prefix': '/data/user_uploads/'},
    'write_file':   {'allowed': True,  'path_prefix': '/data/user_uploads/'},
    'delete_file':  {'allowed': False, 'reason': 'Requires human approval'},
    'send_email':   {'allowed': True,  'max_recipients': 1},
    'execute_code': {'allowed': False, 'reason': 'Not permitted in this deployment'},
}

def action_guardrail(tool_name: str, args: dict) -> tuple[bool, str]:
    policy = TOOL_POLICY.get(tool_name)
    if not policy:
        return False, f'Unknown tool: {tool_name}'
    if not policy['allowed']:
        return False, policy.get('reason', 'Not permitted')
    if 'path_prefix' in policy:
        if not args.get('path','').startswith(policy['path_prefix']):
            return False, f'Path must be within {policy["path_prefix"]}'
    if 'max_recipients' in policy:
        if len(args.get('to',[])) > policy['max_recipients']:
            return False, f'Max {policy["max_recipients"]} recipient(s)'
    return True, 'allowed'

from dataclasses import dataclass, field
from collections import deque

@dataclass
class ConversationGuard:
    window: int = 10
    escalation_threshold: float = 0.6
    _risk_scores: deque = field(default_factory=lambda: deque(maxlen=10))

    def record_turn(self, risk_score: float) -> None:
        self._risk_scores.append(risk_score)

    @property
    def trajectory_risk(self) -> float:
        """Exponentially weighted recent risk — recent turns count more."""
        if not self._risk_scores:
            return 0.0
        scores = list(self._risk_scores)
        weights = [0.9 ** (len(scores) - i - 1) for i in range(len(scores))]
        return sum(s * w for s, w in zip(scores, weights)) / sum(weights)

    def should_escalate(self) -> bool:
        return self.trajectory_risk > self.escalation_threshold

    def escalation_response(self) -> str:
        return ('I have noticed this conversation is moving in a direction I cannot continue. '
                'If you have a legitimate need, please contact support.')

# Usage in a conversation loop
guard = ConversationGuard()

def process_turn(user_msg: str, risk_classifier) -> str:
    risk = risk_classifier(user_msg)  # returns float 0-1
    guard.record_turn(risk)
    if guard.should_escalate():
        return guard.escalation_response()
    return main_llm_call(user_msg)
